/* eslint-disable no-inner-declarations, func-names, no-console */
(function () {
  if (
    window.parent &&
    window !== window.parent &&
    !window.__BIT_ERROR_REPORTER_INSTALLED__
  ) {
    window.__BIT_ERROR_REPORTER_INSTALLED__ = true;
    function getBitContext() {
      try {
        const url = window.location.href;
        const { hash, search } = window.location;

        const [componentIdPart, hashQuery = ''] = hash.slice(1).split('?');
        const componentId = componentIdPart || '';

        const queryString = hashQuery || search.slice(1);
        const params = new URLSearchParams(queryString);

        const previewType = params.get('preview') || '';
        const envId = params.get('env') || '';
        const compositionName = params.get('name') || '';

        let scope = '';
        let name = '';

        if (componentId) {
          const parts = componentId.split('/');
          if (parts.length >= 2) {
            [scope] = parts;
            name = parts.slice(1).join('/');
          }
        }

        return {
          url,
          component: {
            id: componentId,
            scope,
            name,
          },
          previewType,
          envId,
          compositionName,
        };
      } catch (e) {
        console.warn('Failed to parse Bit context from URL', e);
        return {
          url: window.location.href,
          parseError: true,
        };
      }
    }

    const bitContext = getBitContext();

    function sanitizeErrorForSerialization(error) {
      if (!error) return null;

      if (error instanceof Error) {
        return {
          name: error.name,
          message: error.message,
          stack: error.stack,
        };
      }

      if (typeof error === 'object') {
        try {
          return JSON.parse(JSON.stringify(error));
        } catch (e) {
          return String(error);
        }
      }

      return String(error);
    }

    function sendErrorToParent(errorData) {
      try {
        const enrichedData = {
          ...errorData,
          context: {
            bit: bitContext,
            userAgent: navigator.userAgent,
            viewport: {
              width: window.innerWidth,
              height: window.innerHeight,
            },
            timestamp: Date.now(),
          },
        };

        window.__LAST_BIT_ERROR__ = enrichedData;
        // Check if postMessage is available
        if (typeof window.parent?.postMessage === 'function') {
          window.parent.postMessage(
            {
              event: '__BIT_PREVIEW_ERROR__',
              payload: enrichedData,
            },
            '*'
          );
        } else {
          console.warn('window.parent.postMessage is not available');
        }
      } catch (e) {
        console.warn('Failed to report error to host:', e);
      }
    }

    window.__originalWindowOnerror = window.onerror;

    function globalErrorHandler(message, source, lineno, colno, error) {
      try {
        sendErrorToParent({
          message: message || 'Unknown error',
          filename: source,
          lineno,
          colno,
          stack: error?.stack,
          error: sanitizeErrorForSerialization(error),
          type: 'global-error',
        });
      } catch (err) {
        console.warn('Error in globalErrorHandler:', err);
      }

      if (
        typeof window.onerror === 'function' &&
        window.__originalWindowOnerror &&
        window.__originalWindowOnerror !== window.onerror
      ) {
        return window.__originalWindowOnerror.call(this, message, source, lineno, colno, error);
      }
      return false;
    }

    window.onerror = globalErrorHandler;

    function errorEventHandler(event) {
      try {
        sendErrorToParent({
          message: event.message || 'Unknown error',
          filename: event.filename,
          lineno: event.lineno,
          colno: event.colno,
          stack: event.error?.stack,
          error: sanitizeErrorForSerialization(event.error),
          type: 'runtime-error',
        });
      } catch (err) {
        console.warn('Error in errorEventHandler:', err);
      }
      return false;
    }
    window.addEventListener('error', errorEventHandler, true);

    function unhandledRejectionHandler(event) {
      try {
        sendErrorToParent({
          message: event.reason?.message || 'Unhandled Promise Rejection',
          stack: event.reason?.stack,
          error: sanitizeErrorForSerialization(event.reason),
          type: 'promise-rejection',
        });
      } catch (err) {
        console.warn('Error in unhandledRejectionHandler:', err);
      }
    }
    window.addEventListener('unhandledrejection', unhandledRejectionHandler);

    const errorPatterns = [
      'Error',
      'Exception',
      'React',
      'component',
      'render',
      'element type',
      'invalid prop',
    ];

    function enhancedConsoleError(...args) {
      try {
        if (typeof window.__originalConsoleError === 'function') {
          window.__originalConsoleError.apply(console, args);
        }

        const errorString = args
          .map((arg) =>
            // eslint-disable-next-line no-nested-ternary
            typeof arg === 'string'
              ? arg
              : arg instanceof Error
              ? arg.message
              : String(arg)
          )
          .join(' ');

        if (errorPatterns.some((pattern) => errorString.includes(pattern))) {
          const errors = args.filter((arg) => arg instanceof Error);
          const errorObj =
            errors.length > 0 ? errors[0] : new Error(errorString);

          sendErrorToParent({
            message: errorString,
            error: sanitizeErrorForSerialization(errorObj),
            type: 'console-error',
          });
        }
      } catch (err) {
        console.warn('Error in enhancedConsoleError:', err);
        if (typeof window.__originalConsoleError === 'function') {
          window.__originalConsoleError.apply(console, args);
        }
      }
    }

    window.__originalConsoleError = console.error;
    console.error = enhancedConsoleError;

    function reactErrorOverlayHandler(error) {
      try {
        if (typeof window.__originalReportRuntimeError === 'function') {
          window.__originalReportRuntimeError.call(this, error);
        }

        sendErrorToParent({
          message: error?.message || 'React Error',
          stack: error?.stack,
          error: sanitizeErrorForSerialization(error),
          type: 'react-error',
        });
      } catch (err) {
        console.warn('Error in reactErrorOverlayHandler:', err);
      }
    }

    window.__REACT_ERROR_OVERLAY_GLOBAL_HOOK__ =
      window.__REACT_ERROR_OVERLAY_GLOBAL_HOOK__ || {};
    window.__originalReportRuntimeError =
      window.__REACT_ERROR_OVERLAY_GLOBAL_HOOK__.reportRuntimeError;
    window.__REACT_ERROR_OVERLAY_GLOBAL_HOOK__.reportRuntimeError =
      reactErrorOverlayHandler;

    window.__reportError = function (error, additionalContext) {
      try {
        sendErrorToParent({
          message: error?.message || String(error),
          error: sanitizeErrorForSerialization(error),
          additionalContext,
          type: 'manual-report',
        });
      } catch (err) {
        console.warn('Error in __reportError:', err);
      }
    };

    try {
      if (typeof window.parent?.postMessage === 'function') {
        window.parent.postMessage(
          {
            event: 'ERROR_REPORTER_READY',
            payload: {
              context: {
                bit: bitContext,
                timestamp: Date.now(),
              },
            },
          },
          '*'
        );
      }
    } catch (e) {
      console.warn('Failed to send ready message:', e);
    }
  }
})();
